import org.apache.commons.text.StringEscapeUtils;
import java.io.*;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userInput = br.readLine();

        System.out.println("Hello, " + userInput + "!");

        // Fixed: User input is properly escaped before including in HTML output
        String escapedInput = StringEscapeUtils.escapeHtml4(userInput);
        System.out.println("<h1>Welcome, " + escapedInput + "!</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
